import User from "../models/User.js";
import BankAccount from "../models/BankAccount.js";
import { generateToken } from "../utils/jwt.js";

export const register = async (req, res) => {
  const { name, email, password } = req.body;

  if (!name || !email || !password) {
    return res.status(400).json({ message: "All fields required" });
  }

  const existing = await User.findOne({ email });
  if (existing) {
    return res.status(400).json({ message: "User already exists" });
  }

  // Create user - ConvergeX Wallet auto-generated by Schema default function
  const user = await User.create({
    name,
    email,
    password
  });

  const emailPrefix = email.split("@")[0];
  const upiId = `${emailPrefix}@cxpay`;

  const accountNumber = `CX${Date.now()}${Math.floor(Math.random() * 1000)}`;

  await BankAccount.create({
    userId: user._id,
    upiId,
    accountNumber, // ✅ NEVER NULL
    balance: 10000,
  });

  res.status(201).json({
    token: generateToken(user._id),
    user: {
      id: user._id,
      name: user.name,
      email: user.email,
      // Wallet Details will be fetched on dashboard
    },
  });
};


export const login = async (req, res) => {
  const { email, password } = req.body;

  const user = await User.findOne({ email }).select("+password");
  if (!user || !(await user.comparePassword(password))) {
    return res.status(401).json({ message: "Invalid credentials" });
  }

  res.json({
    token: generateToken(user._id),
    user: {
      id: user._id,
      name: user.name,
      email: user.email,
    },
  });
};

export const getMe = async (req, res) => {
  try {
    const account = await BankAccount.findOne({ userId: req.user._id });

    res.json({
      user: {
        id: req.user._id,
        name: req.user.name,
        email: req.user.email,
        upiId: account?.upiId,
        balance: account?.balance,
      },
    });
  } catch (error) {
    res.status(500).json({ message: "Failed to fetch user data" });
  }
};
